css_variables:
:root {
  /* Primary */
  --color-primary-50: #F2F5FD;
  --color-primary-100: #E5EBFA;
  --color-primary-200: #C3D0F4;
  --color-primary-300: #91ADF2;
  --color-primary-400: #5A83EC;
  --color-primary-500: #0E4EF1;
  --color-primary-600: #0B41CB;
  --color-primary-700: #0936A9;
  --color-primary-800: #0B2B7F;
  --color-primary-900: #092367;
  --color-primary-950: #09183E;

  /* Secondary */
  --color-secondary-50: #FDFAF2;
  --color-secondary-100: #FAF4E5;
  --color-secondary-200: #F4E6C3;
  --color-secondary-300: #F2D791;
  --color-secondary-400: #ECC35A;
  --color-secondary-500: #F1B10E;
  --color-secondary-600: #CB950B;
  --color-secondary-700: #A97C09;
  --color-secondary-800: #7F5E0B;
  --color-secondary-900: #674D09;
  --color-secondary-950: #3E2F09;

  /* Neutral */
  --color-neutral-50: #F7F7F8;
  --color-neutral-100: #F1F2F4;
  --color-neutral-200: #E3E4E8;
  --color-neutral-300: #CDCFD6;
  --color-neutral-400: #9A9FAC;
  --color-neutral-500: #646E87;
  --color-neutral-600: #4E566A;
  --color-neutral-700: #3B404F;
  --color-neutral-800: #272B35;
  --color-neutral-900: #181A20;
  --color-neutral-950: #0D0E12;

  /* Semantic */
  --color-success: #10B981;
  --color-success-light: #D1FAE5;
  --color-success-dark: #065F46;
  --color-success-50: #ECFDF5;
  --color-success-500: #10B981;
  --color-success-600: #059669;
  --color-success-700: #047857;
  --color-warning: #F59E0B;
  --color-warning-light: #FEF3C7;
  --color-warning-dark: #92400E;
  --color-warning-50: #FFFBEB;
  --color-warning-500: #F59E0B;
  --color-warning-600: #D97706;
  --color-warning-700: #B45309;
  --color-error: #EF4444;
  --color-error-light: #FEE2E2;
  --color-error-dark: #991B1B;
  --color-error-50: #FEF2F2;
  --color-error-500: #EF4444;
  --color-error-600: #DC2626;
  --color-error-700: #B91C1C;
  --color-info: #3B82F6;
  --color-info-light: #DBEAFE;
  --color-info-dark: #1E40AF;
  --color-info-50: #EFF6FF;
  --color-info-500: #3B82F6;
  --color-info-600: #2563EB;
  --color-info-700: #1D4ED8;

  /* Dark Mode (apply via [data-theme="dark"]) */
  --dark-background: #0B0D14;
  --dark-surface: #181C25;
  --dark-surface-elevated: #262A36;
  --dark-text-primary: #F1F2F4;
  --dark-text-secondary: #B9BCC6;
  --dark-text-muted: #737A8C;
  --dark-border: #303441;
}
